function bizDate(n){const r=new Date();let a=0;while(a<n){r.setDate(r.getDate()+1);if(r.getDay()!==0&&r.getDay()!==6)a++;}return r;}
function fmtD(d){return d.toLocaleDateString("fr-FR",{day:"numeric",month:"long"});}
function getDelivery(){return`${fmtD(bizDate(3))} – ${fmtD(bizDate(5))}`;}
function getGreeting(){const h=new Date().getHours();return h<12?"Bonjour":h<18?"Bon après-midi":"Bonsoir";}
function getVisitors(){
  const h=new Date().getHours();
  const base=h>=19?18:h>=14?14:h>=10?10:h>=7?6:3;
  const seed=Math.floor(Date.now()/3600000);
  return Math.min(22,Math.max(5,base+((seed*1664525+1013904223)&0x7fffffff)%8-3));
}

function useScrollPct(){
  const[p,setP]=useState(0);
  useEffect(()=>{
    const h=()=>{const t=document.documentElement.scrollHeight-window.innerHeight;setP(t>0?Math.min(100,Math.round(window.scrollY/t*100)):0);};
    window.addEventListener("scroll",h,{passive:true});return()=>window.removeEventListener("scroll",h);
  },[]);return p;
}

function useVis(ref){
  const[ratio,setRatio]=useState(0),[entered,setEntered]=useState(false),[just,setJust]=useState(false),prev=useRef(0);
  useEffect(()=>{
    const el=ref.current;if(!el)return;
    const fire=()=>{setJust(true);setTimeout(()=>setJust(false),900);};
    const obs=new IntersectionObserver(([e])=>{
      const r=e.intersectionRatio;
      if(r>.15&&!entered){setEntered(true);fire();}
      if(r>.4&&prev.current<=.4)fire();
      prev.current=r;setRatio(r);
    },{threshold:[0,.1,.15,.2,.3,.4,.5,.6,.7,.8,.9,1]});
    obs.observe(el);return()=>obs.disconnect();
  },[ref,entered]);
  return{ratio,entered,just};
}

function useActiveStep(){
  const[a,setA]=useState(0);
  useEffect(()=>{
    const ids=["s1","s2","s3","s4","s5","s6"];
    const h=()=>{let f=0;ids.forEach((id,i)=>{const el=document.getElementById(id);if(el&&el.getBoundingClientRect().top<window.innerHeight*.55)f=i+1;});setA(f);};
    window.addEventListener("scroll",h,{passive:true});return()=>window.removeEventListener("scroll",h);
  },[]);return a;
}

function useIdleTimer(onIdle,delay=30000){
  useEffect(()=>{
    let t=setTimeout(onIdle,delay);
    const reset=()=>{clearTimeout(t);t=setTimeout(onIdle,delay);};
    ["mousemove","touchstart","scroll","keydown"].forEach(e=>window.addEventListener(e,reset,{passive:true}));
    return()=>{clearTimeout(t);["mousemove","touchstart","scroll","keydown"].forEach(e=>window.removeEventListener(e,reset));};
  },[onIdle,delay]);
}

// ── Audio Engine ─────────────────────────────────────────────────
const AudioEngine = (function(){
  let ctx=null,gainNode=null,loopSrc=null,muted=false;
  function getCtx(){
    if(!ctx){ctx=new(window.AudioContext||window.webkitAudioContext)();gainNode=ctx.createGain();gainNode.gain.value=0;gainNode.connect(ctx.destination);}
    return ctx;
  }
  function startLofi(){
    const c=getCtx();
    function makeNote(freq,time,dur,vol=0.04){
      const o=c.createOscillator(),g=c.createGain(),filter=c.createBiquadFilter();
      filter.type="lowpass";filter.frequency.value=800;
      o.connect(filter);filter.connect(g);g.connect(gainNode);
      o.type="sine";o.frequency.value=freq;
      g.gain.setValueAtTime(0,time);g.gain.linearRampToValueAtTime(vol,time+0.05);
      g.gain.exponentialRampToValueAtTime(0.001,time+dur);
      o.start(time);o.stop(time+dur+0.1);
    }
    const chord=[196,246.94,293.66,369.99];
    const now=c.currentTime;
    let t=now;
    function loop(){
      chord.forEach((f,i)=>{makeNote(f,t+i*0.08,2.5,0.03);});
      t+=3;
      if(t-now<30)loop();
    }
    loop();
    // Fade in
    gainNode.gain.setValueAtTime(0,now);
    gainNode.gain.linearRampToValueAtTime(muted?0:0.18,now+3);
    setTimeout(()=>{if(!muted)startLofi();},28000);
  }
  function playWhoosh(){
    try{
      const c=getCtx();
      const buf=c.createBuffer(1,c.sampleRate*0.4,c.sampleRate);
      const d=buf.getChannelData(0);
      for(let i=0;i<d.length;i++)d[i]=(Math.random()*2-1)*Math.pow(1-i/d.length,2)*0.3;
      const src=c.createBufferSource(),g=c.createGain(),filter=c.createBiquadFilter();
      filter.type="highpass";filter.frequency.value=200;
      src.buffer=buf;src.connect(filter);filter.connect(g);g.connect(gainNode);
      g.gain.setValueAtTime(0.6,c.currentTime);g.gain.exponentialRampToValueAtTime(0.001,c.currentTime+0.4);
      src.start(c.currentTime);
    }catch(e){}
  }
  function playPop(){
    try{
      const c=getCtx(),now=c.currentTime;
      [880,1100,1320].forEach((f,i)=>{
        const o=c.createOscillator(),g=c.createGain();
        o.connect(g);g.connect(gainNode);
        o.type="sine";o.frequency.setValueAtTime(f*1.2,now+i*.04);
        o.frequency.exponentialRampToValueAtTime(f,now+i*.04+.08);
        g.gain.setValueAtTime(0,now+i*.04);g.gain.linearRampToValueAtTime(.12,now+i*.04+.01);
        g.gain.exponentialRampToValueAtTime(.001,now+i*.04+.15);
        o.start(now+i*.04);o.stop(now+i*.04+.2);
      });
    }catch(e){}
  }
  function playCrescendo(){
    try{
      const c=getCtx(),now=c.currentTime;
      gainNode.gain.linearRampToValueAtTime(0.28,now+2);
      setTimeout(()=>{if(!muted)gainNode.gain.linearRampToValueAtTime(0.18,c.currentTime+2);},3000);
    }catch(e){}
  }
  function toggleMute(){
    muted=!muted;
    if(gainNode){
      const now=getCtx().currentTime;
      gainNode.gain.linearRampToValueAtTime(muted?0:0.18,now+0.5);
    }
    return muted;
  }
  function init(){try{getCtx();startLofi();}catch(e){}}
  return{init,playWhoosh,playPop,playCrescendo,toggleMute,isMuted:()=>muted};
})();

// ── Custom cursor ─────────────────────────────────────────────────
function CustomCursor(){
  const ref=useRef(null);
  useEffect(()=>{
    const el=ref.current;if(!el)return;
    const mv=e=>{el.style.left=e.clientX+"px";el.style.top=e.clientY+"px";};
    const md=()=>el.classList.add("clicking");
    const mu=()=>el.classList.remove("clicking");
    window.addEventListener("mousemove",mv);window.addEventListener("mousedown",md);window.addEventListener("mouseup",mu);
    return()=>{window.removeEventListener("mousemove",mv);window.removeEventListener("mousedown",md);window.removeEventListener("mouseup",mu);};
  },[]);
  return<div ref={ref} className="cursor"/>;
}

