// ── StepCard ──────────────────────────────────────────────────────
function StepCard({n,icon,title,desc,children,highlight,id,isActive,isCopied,sc,idleOn}){
  const ref=useRef(null);
  const{ratio,entered,just}=useVis(ref);
  const[aura,setAura]=useState(false),[scan,setScan]=useState(false),[ripple,setRipple]=useState(false);
  const ran=useRef(false);
  useEffect(()=>{
    if(just&&!ran.current){ran.current=true;setAura(true);setScan(true);setRipple(true);
      setTimeout(()=>setAura(false),800);setTimeout(()=>setScan(false),700);setTimeout(()=>setRipple(false),900);}
  },[just]);
  const col=sc?.ac||GREEN;
  const opacity=entered?(isActive?1:.35):0;
  const blurV=entered?(isActive?"none":"blur(2px)"):"none";
  const scale=entered?(isActive?1:.96):.92;
  const ty=entered?0:40;
  const shadow=isActive?`0 0 0 1px ${col}44, 0 16px 60px ${sc?.gl||GREENGL}, 0 4px 16px rgba(0,0,0,.4)`:
    isCopied?`0 0 0 1px ${col}33`:"0 2px 12px rgba(0,0,0,.3)";
  const borderC=isCopied?`${col}66`:isActive?`${col}44`:"rgba(255,255,255,.06)";
  const cardBg=isActive?"rgba(255,255,255,.06)":isCopied?"rgba(74,200,120,.04)":"rgba(255,255,255,.03)";

  return(
    <div ref={ref} id={id} style={{background:cardBg,border:`1.5px solid ${borderC}`,borderRadius:"24px",overflow:"hidden",position:"relative",opacity,transform:`translateY(${ty}px) scale(${scale})`,filter:blurV,boxShadow:shadow,transition:"transform .55s cubic-bezier(.16,1,.3,1),opacity .55s ease,box-shadow .4s,filter .4s,border-color .4s,background .4s",willChange:"transform,opacity,filter"}}>
      <Halo color={col} show={isActive}/>
      {/* Big watermark */}
      <div style={{position:"absolute",right:"-6px",top:"-10px",fontSize:"120px",fontWeight:900,color:isActive?`${col}10`:"rgba(255,255,255,.02)",fontFamily:PP,lineHeight:1,pointerEvents:"none",userSelect:"none",zIndex:0,transition:"color .4s"}}>{String(n).padStart(2,"0")}</div>
      {aura&&<div style={{position:"absolute",inset:0,borderRadius:"24px",zIndex:10,pointerEvents:"none",background:`radial-gradient(ellipse at 50% 30%,${col}20 0%,transparent 70%)`,animation:"auraBurst .75s forwards"}}/>}
      {scan&&<div style={{position:"absolute",left:0,right:0,height:"2px",zIndex:11,pointerEvents:"none",background:`linear-gradient(90deg,transparent,${col}99 30%,${col} 50%,${col}99 70%,transparent)`,animation:"scanline .5s cubic-bezier(.4,0,.6,1) forwards"}}/>}
      <div style={{display:"flex",alignItems:"center",gap:"14px",padding:"18px 20px",borderBottom:"1px solid rgba(255,255,255,.05)",position:"relative",zIndex:1}}>
        <div style={{position:"relative",flexShrink:0}}>
          {ripple&&<><div style={{position:"absolute",inset:0,borderRadius:"14px",background:col,animation:"rippleOut .8s ease-out forwards",zIndex:0}}/><div style={{position:"absolute",inset:0,borderRadius:"14px",background:col,animation:"rippleOut .8s ease-out .15s forwards",zIndex:0}}/></>}
          <div style={{width:"50px",height:"50px",borderRadius:"16px",background:isCopied?col:`${col}18`,display:"flex",alignItems:"center",justifyContent:"center",position:"relative",zIndex:1,transform:isActive?"scale(1.08)":"scale(1)",transition:"transform .4s cubic-bezier(.34,1.56,.64,1),background .3s",color:isCopied?"#000":col,boxShadow:isActive?`0 4px 20px ${col}44`:0}}>
            {isCopied?<ICheck s={22} c="#000"/>:icon}
          </div>
        </div>
        <div style={{flex:1,zIndex:1}}>
          <GlitchLabel n={n} active={just} color={col}/>
          <div style={{fontSize:"16px",fontWeight:700,color:TX,marginTop:"3px",lineHeight:"1.3",fontFamily:PP}}>{title}</div>
        </div>
        {isCopied&&<span style={{fontSize:"11px",fontWeight:700,color:col,fontFamily:FF,background:`${col}18`,padding:"4px 10px",borderRadius:"10px",flexShrink:0}}>✓ Fait</span>}
      </div>
      <div style={{padding:"18px 20px",position:"relative",zIndex:1}}>
        {desc&&<p style={{fontSize:"13px",color:TM,margin:"0 0 14px",lineHeight:"1.6",fontFamily:FF}}>{desc}</p>}
        {children}
        {isActive&&!isCopied&&(
          <div style={{marginTop:"12px",textAlign:"center",fontSize:"11px",color:TL,fontFamily:FF,padding:"6px",background:"rgba(255,255,255,.02)",borderRadius:"8px"}}>
            ✓ 100% des clients réussissent cette étape
          </div>
        )}
      </div>
    </div>
  );
}

