// ── Payment Page ──────────────────────────────────────────────────
function PaymentPage({data}){
  const[showIntro,setShowIntro]=useState(true);
  const[show,setShow]=useState(false);
  const[showFinish,setShowFinish]=useState(false);
  const[muted,setMuted]=useState(false);
  const[idle,setIdle]=useState(false);
  const pct=useScrollPct(),activeStep=useActiveStep();
  const[ci,setCi]=useState(false),[cn,setCn]=useState(false),[ca,setCa]=useState(false),[cr,setCr]=useState(false);
  const all=ci&&cn&&ca&&cr;
  const copiedCount=[ci,cn,ca,cr].filter(Boolean).length;
  const visitors=useRef(getVisitors()).current;

  useEffect(()=>{setTimeout(()=>setShow(true),50);},[]);

  // Crescendo near end
  useEffect(()=>{if(activeStep>=5)AudioEngine.playCrescendo();},[activeStep]);

  // Idle detection
  useIdleTimer(useCallback(()=>setIdle(true),[]),30000);
  useEffect(()=>{
    const reset=()=>setIdle(false);
    ["touchstart","mousemove","scroll"].forEach(e=>window.addEventListener(e,reset,{passive:true}));
    return()=>["touchstart","mousemove","scroll"].forEach(e=>window.removeEventListener(e,reset));
  },[]);

  const scrollTo=id=>setTimeout(()=>{const el=document.getElementById(id);if(el)el.scrollIntoView({behavior:"smooth",block:"center"});},400);

  const waText=`Bonjour, j'ai effectué mon virement de ${data.amount}€ pour ma commande${data.order?` #${data.order}`:""
}. Voici ma capture.`;
  const waLink=`https://wa.me/447365758255?text=${encodeURIComponent(waText)}`;
  const handleWa=e=>{e.preventDefault();setShowFinish(true);setTimeout(()=>window.open(waLink,"_blank"),800);};

  if(showIntro)return(
    <IntroScreen name={data.name} onStart={()=>{AudioEngine.playWhoosh();setShowIntro(false);}}/>
  );
  if(showFinish)return<FinishScreen name={data.name} waLink={waLink} onWa={e=>{e.preventDefault();window.open(waLink,"_blank");}} />;

  return(
    <div style={{minHeight:"100vh",background:BG,fontFamily:FF,opacity:show?1:0,transition:"opacity .5s ease",position:"relative",paddingBottom:"90px"}}>
      <CustomCursor/>
      <Bubbles/>

      {/* Progress bar */}
      <div style={{position:"fixed",top:0,left:0,width:"100%",height:"3px",zIndex:100}}>
        <div style={{height:"100%",width:`${pct}%`,background:`linear-gradient(90deg,${GREEN},#7EC8A0)`,transition:"width .1s linear",borderRadius:"0 2px 2px 0"}}/>
      </div>

      {/* Header */}
      <div style={{position:"sticky",top:"3px",zIndex:90,backdropFilter:"blur(24px)",background:"rgba(13,13,13,.94)",borderBottom:"1px solid rgba(255,255,255,.06)"}}>
        <div style={{maxWidth:"460px",margin:"0 auto",padding:"12px 16px",display:"flex",alignItems:"center",justifyContent:"space-between"}}>
          <div style={{fontSize:"10px",fontWeight:800,letterSpacing:"4px",color:TX,fontFamily:PP}}>QUATTRO</div>
          <ProgressDots ci={ci} cn={cn} ca={ca} cr={cr}/>
          <button onClick={()=>setMuted(AudioEngine.toggleMute())} className="bp" style={{background:"transparent",border:"none",color:TL,cursor:"pointer",padding:"4px"}}>
            <IMute muted={muted}/>
          </button>
        </div>
        {/* Sticky instruction */}
        <div style={{background:`${GREEN}12`,borderTop:"1px solid rgba(74,200,120,.15)",padding:"8px 16px",textAlign:"center"}}>
          <div style={{fontSize:"11px",color:GREEN,fontWeight:700,fontFamily:FF,letterSpacing:".3px"}}>👆 Appuyez sur COPIER à chaque étape — puis collez dans votre app bancaire</div>
        </div>
      </div>

      <div style={{display:"flex",flexDirection:"column",alignItems:"center",padding:"24px 16px 20px",position:"relative",zIndex:1}}>
        <div style={{width:"100%",maxWidth:"460px"}}>

          {/* Title */}
          <div style={{textAlign:"center",marginBottom:"32px",animation:"fadeUp .7s ease"}}>
            <div style={{display:"flex",alignItems:"center",gap:"12px",justifyContent:"center",marginBottom:"16px"}}>
              <div style={{height:"1px",flex:1,background:"linear-gradient(90deg,transparent,rgba(255,255,255,.1))"}}/>
              <div style={{fontSize:"11px",color:TL,letterSpacing:"3px",textTransform:"uppercase",fontFamily:FF}}>6 étapes · 2 minutes</div>
              <div style={{height:"1px",flex:1,background:"linear-gradient(90deg,rgba(255,255,255,.1),transparent)"}}/>
            </div>
            <div style={{fontSize:"34px",fontWeight:900,color:TX,fontFamily:PP,letterSpacing:"-1px",lineHeight:"1.05"}}>Votre virement</div>
            <div style={{fontSize:"34px",fontWeight:900,color:GREEN,fontFamily:PP,letterSpacing:"-1px",lineHeight:"1.05"}}>en 6 étapes</div>
            <div style={{height:"3px",width:"48px",background:GREEN,borderRadius:"2px",margin:"14px auto 0",boxShadow:`0 0 12px ${GREEN}`}}/>
            <div style={{display:"flex",gap:"8px",justifyContent:"center",marginTop:"18px",flexWrap:"wrap"}}>
              <span style={{padding:"6px 14px",background:GREENGL,borderRadius:"20px",border:`1px solid ${GREEN}30`,fontSize:"12px",color:GREEN,fontFamily:FF}}>🔒 Paiement sécurisé</span>
              <span style={{padding:"6px 14px",background:"rgba(255,255,255,.04)",borderRadius:"20px",border:"1px solid rgba(255,255,255,.08)",fontSize:"12px",color:TM,fontFamily:FF}}>👥 {visitors} paiements aujourd'hui</span>
            </div>
          </div>

          {/* Steps */}
          <div style={{display:"flex",flexDirection:"column",gap:"0"}}>

            <StepCard n={1} icon={<IBank c={STEP_COLORS[0].ac}/>} title="Ouvrez votre app bancaire" id="s1" isActive={activeStep<=1} isCopied={false} sc={STEP_COLORS[0]}
              desc="Cherchez le bouton Paiements → puis Virement bancaire ou Envoyer de l'argent.">
              <BankCarousel/>
              <AltNames names={["Virement bancaire","Envoyer de l'argent","Nouveau virement","Virement SEPA"]}/>
            </StepCard>

            <StepArrow done={false} color={STEP_COLORS[0].ac}/>

            <StepCard n={2} icon={<IIban c={STEP_COLORS[1].ac}/>} title="Copiez l'IBAN" id="s2" isActive={activeStep===2} isCopied={ci} sc={STEP_COLORS[1]}
              desc="Numéro du compte vers lequel envoyer l'argent. Copiez-le et collez-le dans votre app.">
              <CopyRow label="IBAN" value="LU80 4080 0000 4547 7817" copyValue="LU80408000004547817" onCopied={()=>{setCi(true);scrollTo("s3");}} color={STEP_COLORS[1].ac} idle={idle&&activeStep===2}/>
              <Tip icon="🇱🇺" text="Si votre banque demande un pays, sélectionnez Luxembourg."/>
            </StepCard>

            <StepArrow done={ci} color={STEP_COLORS[1].ac}/>

            <StepCard n={3} icon={<IUser c={STEP_COLORS[2].ac}/>} title="Nom du bénéficiaire" id="s3" isActive={activeStep===3} isCopied={cn} sc={STEP_COLORS[2]}
              desc="Entrez le nom du destinataire. Ce champ peut s'appeler : Bénéficiaire, Destinataire, Titulaire.">
              <CopyRow label="Nom à entrer" value="Quattro Visual Ltd" sublabel={<><Tooltip text="Quattro Visual Ltd est le nom légal de Quattro Shopping, entreprise enregistrée en Europe.">C'est quoi ?</Tooltip> — Entreprise enregistrée au Royaume-Uni</>} onCopied={()=>{setCn(true);scrollTo("s4");}} color={STEP_COLORS[2].ac} idle={idle&&activeStep===3}/>
            </StepCard>

            <StepArrow done={ci&&cn} color={STEP_COLORS[2].ac}/>

            <StepCard n={4} icon={<IEuro c={STEP_COLORS[3].ac}/>} title="Montant exact" id="s4" isActive={activeStep===4} isCopied={ca} sc={STEP_COLORS[3]}
              desc="Vérifiez que la devise est bien en euros (€).">
              <CopyRow isSlot amount={data.amount} value={`${data.amount}€`} copyValue={String(data.amount)} large onCopied={()=>{setCa(true);scrollTo("s5");}} color={STEP_COLORS[3].ac} idle={idle&&activeStep===4}/>
            </StepCard>

            <StepArrow done={ci&&cn&&ca} color={STEP_COLORS[3].ac}/>

            <StepCard n={5} icon={<IPen c={STEP_COLORS[4].ac}/>} title="Référence / Motif" id="s5" isActive={activeStep===5} isCopied={cr} sc={STEP_COLORS[4]}
              desc="Ce champ peut s'appeler : Référence, Communication, Motif, Message.">
              <AltNames names={["Référence","Communication","Motif","Message"]}/>
              <CopyRow label="Référence" value={data.name} onCopied={()=>{setCr(true);scrollTo("s6");}} color={STEP_COLORS[4].ac} idle={idle&&activeStep===5}/>
              <Tip text="Si votre banque ne demande pas de référence, passez directement à l'étape suivante."/>
            </StepCard>

            <StepArrow done={all} color={GREEN}/>

            {all&&(
              <div style={{padding:"16px",background:GREENGL,borderRadius:"20px",border:`1.5px solid ${GREEN}44`,display:"flex",alignItems:"center",gap:"12px",animation:"bannerIn .5s cubic-bezier(.16,1,.3,1)",boxShadow:`0 4px 24px ${GREEN}33`,marginBottom:"0"}}>
                <span style={{fontSize:"28px"}}>🎉</span>
                <div>
                  <div style={{fontSize:"15px",fontWeight:700,color:GREEN,fontFamily:PP}}>Tout est copié !</div>
                  <div style={{fontSize:"12px",color:TM,marginTop:"2px",fontFamily:FF}}>Confirmez le virement dans votre app bancaire.</div>
                </div>
              </div>
            )}

            <div style={{height:"10px"}}/>

            <StepCard n={6} icon={<ICheck s={22} c={GREEN}/>} title="Confirmez et envoyez la capture" id="s6" highlight isActive={activeStep===6} isCopied={false} sc={STEP_COLORS[5]}
              desc="Confirmez dans votre app, prenez une capture de la confirmation, puis envoyez-la nous.">
              <div style={{display:"flex",alignItems:"center",gap:"8px",fontSize:"12px",color:TM,marginBottom:"14px"}}>
                <span>📬</span><span>Commande préparée dès réception de votre capture.</span>
              </div>
              {all?(
                <a href={waLink} onClick={handleWa} className="bp" style={{display:"flex",alignItems:"center",justifyContent:"center",gap:"10px",background:"#25D366",color:"#fff",borderRadius:"16px",padding:"18px",fontSize:"16px",fontWeight:700,textDecoration:"none",fontFamily:PP,boxShadow:"0 8px 28px rgba(37,211,102,.5)",animation:"pulse 1.5s ease infinite"}}>
                  <IWa s={22}/> Envoyer la capture sur WhatsApp
                </a>
              ):(
                <div style={{padding:"16px",background:"rgba(255,255,255,.03)",borderRadius:"14px",textAlign:"center",fontSize:"12px",color:TL,fontFamily:FF,border:"1px dashed rgba(255,255,255,.08)"}}>
                  Complétez les 4 étapes ci-dessus pour débloquer
                </div>
              )}
              <div style={{marginTop:"10px",textAlign:"center"}}>
                <a href={waLink} style={{fontSize:"11px",color:TL,fontFamily:FF,textDecoration:"none"}}>J'ai un problème — contacter le support</a>
              </div>
            </StepCard>
          </div>

          {/* Bank logos */}
          <div style={{marginTop:"24px",padding:"18px",background:"rgba(255,255,255,.03)",border:"1px solid rgba(255,255,255,.07)",borderRadius:"18px"}}>
            <div style={{fontSize:"10px",fontWeight:600,letterSpacing:"2px",color:TL,textTransform:"uppercase",marginBottom:"12px"}}>Compatible avec toutes les banques</div>
            <BankLogos/>
          </div>

          <div style={{display:"flex",flexDirection:"column",gap:"10px",marginTop:"12px"}}>
            <Reviews/>
            <div style={{padding:"16px 18px",background:GREENGL,borderRadius:"18px",border:`1px solid ${GREEN}25`}}>
              <div style={{fontSize:"12px",color:GREEN,fontWeight:600,fontFamily:FF,marginBottom:"6px"}}>📦 Livraison estimée</div>
              <div style={{fontSize:"18px",color:TX,fontWeight:700,fontFamily:PP}}>{getDelivery()}</div>
              <div style={{fontSize:"11px",color:TM,marginTop:"4px",fontFamily:FF}}>Suivi UPS/FedEx sous 48h après expédition</div>
            </div>
          </div>

          <div style={{textAlign:"center",marginTop:"28px",paddingBottom:"16px"}}>
            <div style={{fontSize:"10px",fontWeight:800,letterSpacing:"4px",color:TL,marginBottom:"4px",fontFamily:PP}}>QUATTRO</div>
            <div style={{fontSize:"11px",color:TL}}>depuis 2021 · Merci pour votre confiance</div>
            <a href="https://quattroshopping.com" style={{fontSize:"11px",color:GREEN,textDecoration:"none"}}>quattroshopping.com</a>
          </div>
        </div>
      </div>

      <RecapBar ci={ci} cn={cn} ca={ca} cr={cr}/>

      {all&&(
        <a href={waLink} onClick={handleWa} className="bp" style={{position:"fixed",bottom:"82px",right:"18px",zIndex:50,width:"58px",height:"58px",borderRadius:"50%",background:"#25D366",display:"flex",alignItems:"center",justifyContent:"center",boxShadow:"0 4px 24px rgba(37,211,102,.5)",textDecoration:"none",cursor:"pointer",animation:"waBounce 1.5s ease-in-out infinite"}}>
          <IWa s={26}/>
        </a>
      )}
    </div>
  );
}

// ── Admin ─────────────────────────────────────────────────────────
function AdminPanel(){
  const[name,setName]=useState(""),[amount,setAmount]=useState(""),[order,setOrder]=useState(""),[link,setLink]=useState(""),[preview,setPreview]=useState(null);
  const BASE=window.location.origin+window.location.pathname;
  const gen=()=>{if(!name||!amount)return;const p=new URLSearchParams();p.set("name",name);p.set("amount",amount);if(order)p.set("order",order);setLink(`${BASE}?${p.toString()}`);};
  if(preview)return<div><PaymentPage data={preview}/><button onClick={()=>setPreview(null)} className="bp" style={{position:"fixed",top:"60px",left:"16px",zIndex:200,background:"#333",color:"#fff",border:"none",borderRadius:"8px",padding:"8px 14px",fontSize:"12px",cursor:"pointer",fontFamily:FF}}>← Admin</button></div>;
  const inp={width:"100%",padding:"11px 14px",background:"rgba(255,255,255,.05)",border:"1px solid rgba(255,255,255,.1)",borderRadius:"10px",fontSize:"14px",color:TX,outline:"none",fontFamily:FF};
  return(
    <div style={{minHeight:"100vh",background:BG,display:"flex",flexDirection:"column",alignItems:"center",padding:"40px 16px",fontFamily:FF}}>
      <Bubbles/>
      <div style={{textAlign:"center",marginBottom:"28px",zIndex:1}}>
        <div style={{fontSize:"11px",fontWeight:800,letterSpacing:"4px",color:TX,fontFamily:PP}}>QUATTRO</div>
        <div style={{fontSize:"12px",color:GREEN,marginTop:"4px",letterSpacing:"1px"}}>Génération de lien de paiement</div>
      </div>
      <div style={{background:"rgba(255,255,255,.04)",borderRadius:"18px",padding:"28px",width:"100%",maxWidth:"400px",border:"1px solid rgba(255,255,255,.08)",zIndex:1}}>
        {[{label:"Prénom et nom du client",value:name,set:setName,ph:"Jean Dupont"},{label:"Montant (€)",value:amount,set:setAmount,ph:"178"},{label:"N° commande (optionnel)",value:order,set:setOrder,ph:"QS-4521"}].map(f=>(
          <div key={f.label} style={{marginBottom:"16px"}}>
            <label style={{display:"block",fontSize:"10px",fontWeight:600,color:TL,letterSpacing:"1px",textTransform:"uppercase",marginBottom:"6px"}}>{f.label}</label>
            <input value={f.value} onChange={e=>f.set(e.target.value)} placeholder={f.ph} style={inp} onFocus={e=>e.target.style.borderColor=GREEN} onBlur={e=>e.target.style.borderColor="rgba(255,255,255,.1)"}/>
          </div>
        ))}
        <div style={{display:"flex",gap:"8px",marginTop:"8px"}}>
          <button onClick={gen} className="bp" style={{flex:1,padding:"13px",background:GREEN,color:"#000",border:"none",borderRadius:"12px",fontSize:"13px",fontWeight:700,cursor:"pointer",fontFamily:FF}}>Générer le lien</button>
          <button onClick={()=>{if(name&&amount)setPreview({name,amount,order});}} className="bp" style={{padding:"13px 16px",background:"rgba(255,255,255,.06)",color:TX,border:"1px solid rgba(255,255,255,.1)",borderRadius:"12px",fontSize:"13px",fontWeight:600,cursor:"pointer",fontFamily:FF}}>Aperçu</button>
        </div>
        {link&&(
          <div style={{marginTop:"20px",padding:"16px",background:GREENGL,borderRadius:"12px",border:`1px solid ${GREEN}30`}}>
            <div style={{fontSize:"10px",fontWeight:600,color:GREEN,letterSpacing:"1px",textTransform:"uppercase",marginBottom:"8px"}}>Lien généré</div>
            <div style={{fontSize:"11px",color:TM,wordBreak:"break-all",background:"rgba(0,0,0,.3)",borderRadius:"8px",padding:"8px 10px",marginBottom:"10px",fontFamily:"monospace"}}>{link}</div>
            <div style={{display:"flex",gap:"8px",flexWrap:"wrap"}}>
              <CopyBtn text={link} label="Copier le lien" color={GREEN}/>
              <button onClick={()=>{const t=`${getGreeting()} !\n\nMerci pour votre commande Quattro Shopping 🙏\n\nFinalisez votre paiement ici :\n${link}\n\nC'est rapide — 2 minutes max !`;window.open(`https://wa.me/?text=${encodeURIComponent(t)}`,"_blank");}} className="bp" style={{background:"#25D366",color:"#fff",border:"none",borderRadius:"8px",padding:"8px 14px",fontSize:"11px",fontWeight:700,cursor:"pointer",fontFamily:FF}}>Envoyer via WhatsApp</button>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

function LoginScreen({onLogin}){
  const[pw,setPw]=useState(""),[error,setError]=useState(false);
  const go=()=>{if(pw==="eren")onLogin();else{setError(true);setTimeout(()=>setError(false),1500);}};
  return(
    <div style={{minHeight:"100vh",background:BG,display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",padding:"24px",fontFamily:FF}}>
      <Bubbles/>
      <div style={{textAlign:"center",marginBottom:"28px",animation:"fadeUp .5s ease",zIndex:1}}>
        <div style={{fontSize:"11px",fontWeight:800,letterSpacing:"5px",color:TX,fontFamily:PP}}>QUATTRO</div>
        <div style={{fontSize:"12px",color:GREEN,marginTop:"5px",letterSpacing:"1.5px"}}>Espace administration</div>
      </div>
      <div style={{background:"rgba(255,255,255,.04)",borderRadius:"18px",padding:"28px",width:"100%",maxWidth:"340px",border:"1px solid rgba(255,255,255,.08)",zIndex:1}}>
        <div style={{fontSize:"10px",fontWeight:600,color:TL,letterSpacing:"1px",textTransform:"uppercase",marginBottom:"8px"}}>Mot de passe</div>
        <input type="password" value={pw} onChange={e=>setPw(e.target.value)} onKeyDown={e=>e.key==="Enter"&&go()} placeholder="••••••" autoFocus style={{width:"100%",padding:"12px 14px",background:"rgba(255,255,255,.05)",border:`1px solid ${error?"#E24B4A":"rgba(255,255,255,.1)"}`,borderRadius:"10px",fontSize:"16px",color:TX,outline:"none",marginBottom:"12px",fontFamily:FF,transition:"border-color .2s"}}/>
        {error&&<div style={{fontSize:"11px",color:"#E24B4A",marginBottom:"10px",animation:"fadeR .3s ease"}}>Mot de passe incorrect</div>}
        <button onClick={go} className="bp" style={{width:"100%",padding:"13px",background:GREEN,color:"#000",border:"none",borderRadius:"12px",fontSize:"13px",fontWeight:700,cursor:"pointer",fontFamily:FF}}>Accéder</button>
      </div>
    </div>
  );
}

export default function App(){
  const[auth,setAuth]=useState(false);
  const p=new URLSearchParams(window.location.search);
  const name=p.get("name"),amount=p.get("amount"),order=p.get("order");
  if(name&&amount)return<PaymentPage data={{name,amount,order:order||""}}/>;
  if(!auth)return<LoginScreen onLogin={()=>setAuth(true)}/>;
  return<AdminPanel/>;
}
